export const ReviewVideoParams = zod.object({
  videoId: zod.coerce.string(),
});

export const ReviewVideoBody = zod.object({
  action: zod.enum(["approve", "reject"]),
  note: zod.string().optional(),
});

export const ReviewVideoResponse = zod.object({
  id: zod.string(),
  projectId: zod.string(),
  editorId: zod.string(),
  editorName: zod.string(),
  fileName: zod.string(),
  fileSize: zod.string(),
  deliverableIndex: zod.number(),
  submittedAt: zod.string(),
  status: zod.enum(["pending_review", "approved", "rejected"]),
  reviewNote: zod.string().optional(),
  reviewedAt: zod.string().optional(),
  projectName: zod.string().optional(),
  clientName: zod.string().optional(),
});

/**
 * @summary List notifications for a user
 */
export const ListNotificationsParams = zod.object({
  userId: zod.coerce.string(),
});

export const ListNotificationsResponseItem = zod.object({
  id: zod.string(),
  userId: zod.string(),
  type: zod.string(),
  title: zod.string(),
  message: zod.string(),
  projectId: zod.string().optional(),
  videoId: zod.string().optional(),
  read: zod.boolean(),
  createdAt: zod.string(),
});
export const ListNotificationsResponse = zod.array(
  ListNotificationsResponseItem,
);

/**
 * @summary Mark notifications as read
 */
export const MarkNotificationsReadBody = zod.object({
  userId: zod.string(),
  notifIds: zod.array(zod.string()).optional(),
});

export const MarkNotificationsReadResponse = zod.object({
  success: zod.boolean(),
});
